const msg = $input.item.json.message || {};
let text = msg.text || msg.caption || '';
const chatId = msg.chat ? msg.chat.id : 0;

const isRemoveCommand = text.trim().toLowerCase().startsWith('/remove');
const isListCommand = text.trim().toLowerCase().startsWith('/list');
const isHelpCommand = text.trim().toLowerCase().startsWith('/help') || text.trim().toLowerCase().startsWith('/start');

let action = 'add';
let url = '';

if (isHelpCommand) {
  action = 'help';
} else if (isListCommand) {
  action = 'list';
} else if (isRemoveCommand) {
  action = 'remove';
  const parts = text.trim().split(/\s+/);
  if (parts.length >= 2) {
    url = parts[1];
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      url = 'https://' + url;
    }
  }
} else {
  const urlRegex = /https?:\/\/[^\s]+/gi;
  const matches = text.match(urlRegex);
  if (matches && matches.length > 0) {
    url = matches[0];
  } else {
    const domainRegex = /([a-zA-Z0-9-]+\.)+[a-zA-Z]{2,}(\/[^\s]*)?/gi;
    const domainMatches = text.match(domainRegex);
    if (domainMatches && domainMatches.length > 0) {
      url = 'https://' + domainMatches[0];
    }
  }
}

return { json: { action, url, chatId, originalText: text } };

const staticData = $getWorkflowStaticData('global');
if (!staticData.sites) staticData.sites = {};

const url = $input.item.json.url;
const chatId = $input.item.json.chatId;

let message = '';
if (url && staticData.sites[url]) {
  const siteName = staticData.sites[url].name;
  delete staticData.sites[url];
  message = '🗑 Сайт удален из мониторинга:\n🌐 ' + siteName + '\n🔗 ' + url;
} else {
  message = '⚠️ Сайт не найден в мониторинге:\n🔗 ' + (url || '(пусто)');
}

return { json: { message, chatId } };

const staticData = $getWorkflowStaticData('global');
const chatId = $input.item.json.chatId;

if (!staticData.sites || Object.keys(staticData.sites).length === 0) {
  return { json: { message: '📋 Список мониторинга пуст.\nОтправьте URL чтобы добавить сайт.', chatId } };
}

const sites = Object.values(staticData.sites);
let msg = '📋 Сайты в мониторинге (' + sites.length + '):\n\n';
sites.forEach((site, i) => {
  const icon = site.status === 'up' ? '🟢' : site.status === 'down' ? '🔴' : '⚪';
  msg += (i+1) + '. ' + icon + ' ' + site.name + '\n   ' + site.url + '\n';
});

return { json: { message: msg, chatId } };

const staticData = $getWorkflowStaticData('global');
if (!staticData.sites) staticData.sites = {};

const url = $input.item.json.url;
const chatId = $input.item.json.chatId;

let siteName = url;
try { siteName = new URL(url).hostname; } catch(e) {}

staticData.sites[url] = {
  url, name: siteName, chatId,
  status: 'unknown', lastAlert: null,
  addedAt: new Date().toISOString()
};

return { json: { message: '✅ Сайт добавлен в мониторинг:\n🌐 ' + siteName + '\n🔗 ' + url, chatId } };

const staticData = $getWorkflowStaticData('global');

if (!staticData.sites || Object.keys(staticData.sites).length === 0) {
  return [];
}

const results = [];
const sites = Object.values(staticData.sites);

for (const site of sites) {
  let statusCode = 0;
  let isUp = false;
  let errorInfo = '';

  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: site.url,
      timeout: 10000,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    statusCode = resp.statusCode || 200;
    isUp = (statusCode >= 200 && statusCode < 400);
    if (!isUp) errorInfo = 'HTTP ' + statusCode;
  } catch (error) {
    errorInfo = error.message || error.code || 'Connection failed';
    isUp = false;
  }

  const previousStatus = site.status || 'unknown';
  const currentStatus = isUp ? 'up' : 'down';
  let action = 'none';

  if (!isUp && previousStatus !== 'down') {
    action = 'alert_down';
  } else if (isUp && previousStatus === 'down') {
    action = 'alert_recovered';
  }

  staticData.sites[site.url].status = currentStatus;

  if (action !== 'none') {
    const now = new Date().toISOString();
    staticData.sites[site.url].lastAlert = now;

    let message = '';
    if (action === 'alert_down') {
      message = '🔴 САЙТ НЕДОСТУПЕН\n\n' +
        '🌐 Сайт: ' + site.name + '\n' +
        '🔗 URL: ' + site.url + '\n' +
        '❌ Ошибка: ' + errorInfo + '\n' +
        '🕐 Время: ' + now + '\n\n' +
        '⚠️ Повторный алерт не будет отправлен до восстановления.';
    } else {
      message = '🟢 САЙТ ВОССТАНОВЛЕН\n\n' +
        '🌐 Сайт: ' + site.name + '\n' +
        '🔗 URL: ' + site.url + '\n' +
        '✅ Статус: OK (' + statusCode + ')\n' +
        '🕐 Время: ' + now;
    }

    results.push({ json: { chatId: site.chatId, message, action, url: site.url } });
  }
}

return results;
